sql:
SELECT name
FROM hurricanes
WHERE STRFTIME('%Y', start_date) = '2020';

SELECT 
  (SELECT SUM(visualization_size) FROM data_visualizations) + 
  (SELECT SUM(report_size) FROM data_reports) AS total_size;

SELECT AVG(total_damage) AS avg_damage
FROM hurricanes
WHERE year = 2022;

SELECT name, total_casualties
FROM hurricanes
ORDER BY total_casualties DESC;

SELECT user_id, COUNT(*) AS note_count
FROM data_notes
GROUP BY user_id;
